import React, { useState, useEffect, useCallback } from 'react';
import api from '../utils/api';

interface Message {
  id: string;
  canal: string;
  statut: string;
  sentAt: string;
  content?: string;
}

interface Lead {
  id: string;
  nom: string;
  email?: string;
  entreprise?: string;
  secteur?: string;
  score?: number;
  categorie?: string;
  statut: string;
  messages?: Message[];
}

interface Filters {
  search: string;
  categorie: string;
  statut: string;
  page: number;
}

const CATEGORIE_COLORS: Record<string, string> = {
  CHAUD: 'bg-red-500/20 text-red-400 border border-red-500/30',
  TIEDE: 'bg-orange-500/20 text-orange-400 border border-orange-500/30',
  FROID: 'bg-blue-500/20 text-blue-400 border border-blue-500/30',
};

const STATUT_COLORS: Record<string, string> = {
  NOUVEAU: 'text-gray-400',
  CONTACTE: 'text-yellow-400',
  EN_COURS: 'text-blue-400',
  CONVERTI: 'text-green-400',
  PERDU: 'text-red-400',
  BLACKLIST: 'text-gray-600',
};

export default function LeadsPage(): React.ReactElement {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [total, setTotal] = useState<number>(0);
  const [filters, setFilters] = useState<Filters>({ search: '', categorie: '', statut: '', page: 1 });
  const [loading, setLoading] = useState<boolean>(false);

  const fetchLeads = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, any> = { ...filters, limit: 20 };
      Object.keys(params).forEach((k) => !params[k] && delete params[k]);
      const { data } = await api.get('/leads', { params });
      setLeads(data.leads);
      setTotal(data.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    fetchLeads();
  }, [fetchLeads]);

  const deleteLead = async (id: string): Promise<void> => {
    if (!window.confirm('Supprimer ce lead ?')) return;
    await api.delete(`/leads/${id}`);
    fetchLeads();
  };

  const updateStatut = async (id: string, statut: string): Promise<void> => {
    await api.put(`/leads/${id}`, { statut });
    fetchLeads();
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">
          Leads <span className="text-gray-500 text-lg">({total})</span>
        </h1>
        <a
          href="http://localhost:3001/export?format=csv"
          className="px-4 py-2 bg-indigo-600 rounded text-sm hover:bg-indigo-700"
        >
          Exporter CSV
        </a>
      </div>

      {/* Filters */}
      <div className="flex gap-3 flex-wrap">
        <input
          className="bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm w-64"
          placeholder="Rechercher..."
          value={filters.search}
          onChange={(e) => setFilters({ ...filters, search: e.target.value, page: 1 })}
        />
        <select
          className="bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
          value={filters.categorie}
          onChange={(e) => setFilters({ ...filters, categorie: e.target.value, page: 1 })}
        >
          <option value="">Toutes catégories</option>
          <option value="CHAUD">Chaud</option>
          <option value="TIEDE">Tiède</option>
          <option value="FROID">Froid</option>
        </select>
        <select
          className="bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
          value={filters.statut}
          onChange={(e) => setFilters({ ...filters, statut: e.target.value, page: 1 })}
        >
          <option value="">Tous statuts</option>
          {['NOUVEAU', 'CONTACTE', 'EN_COURS', 'CONVERTI', 'PERDU'].map((s) => (
            <option key={s} value={s}>
              {s}
            </option>
          ))}
        </select>
      </div>

      {/* Table */}
      <div className="bg-gray-900 rounded-lg border border-gray-800 overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-800 text-gray-400 text-xs uppercase">
            <tr>
              {['Nom', 'Email', 'Entreprise', 'Secteur', 'Score', 'Catégorie', 'Statut', 'Actions'].map((h) => (
                <th key={h} className="px-4 py-3 text-left">
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-800">
            {loading ? (
              <tr>
                <td colSpan={8} className="text-center py-8 text-gray-500">
                  Chargement...
                </td>
              </tr>
            ) : leads.length === 0 ? (
              <tr>
                <td colSpan={8} className="text-center py-8 text-gray-500">
                  Aucun lead
                </td>
              </tr>
            ) : (
              leads.map((lead) => (
                <tr key={lead.id} className="hover:bg-gray-800/50 transition">
                  <td className="px-4 py-3 font-medium">{lead.nom}</td>
                  <td className="px-4 py-3 text-gray-400">{lead.email || '—'}</td>
                  <td className="px-4 py-3 text-gray-400">{lead.entreprise || '—'}</td>
                  <td className="px-4 py-3 text-gray-400">{lead.secteur || '—'}</td>
                  <td className="px-4 py-3">
                    <span className="font-bold text-white">{lead.score}</span>
                    <span className="text-gray-500">/10</span>
                  </td>
                  <td className="px-4 py-3">
                    <span
                      className={`px-2 py-0.5 rounded text-xs font-medium ${
                        CATEGORIE_COLORS[lead.categorie || ''] || ''
                      }`}
                    >
                      {lead.categorie}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <select
                      className={`bg-transparent text-xs font-medium ${STATUT_COLORS[lead.statut] || ''}`}
                      value={lead.statut}
                      onChange={(e) => updateStatut(lead.id, e.target.value)}
                    >
                      {['NOUVEAU', 'CONTACTE', 'EN_COURS', 'CONVERTI', 'PERDU', 'BLACKLIST'].map((s) => (
                        <option key={s} value={s} className="bg-gray-900 text-white">
                          {s}
                        </option>
                      ))}
                    </select>
                  </td>
                  <td className="px-4 py-3">
                    <button
                      onClick={() => deleteLead(lead.id)}
                      className="text-red-400 hover:text-red-300 text-xs"
                    >
                      Supprimer
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className="flex gap-2 justify-end">
        <button
          disabled={filters.page <= 1}
          onClick={() => setFilters({ ...filters, page: filters.page - 1 })}
          className="px-3 py-1.5 bg-gray-800 rounded text-sm disabled:opacity-40"
        >
          Précédent
        </button>
        <span className="px-3 py-1.5 text-sm text-gray-400">Page {filters.page}</span>
        <button
          disabled={filters.page * 20 >= total}
          onClick={() => setFilters({ ...filters, page: filters.page + 1 })}
          className="px-3 py-1.5 bg-gray-800 rounded text-sm disabled:opacity-40"
        >
          Suivant
        </button>
      </div>
    </div>
  );
}
